#!/usr/bin/env python3
from pathlib import Path
import base64
import re
import shutil
import subprocess
import tempfile

MAIN = Path("lib/main.dart")
PUBSPEC = Path("pubspec.yaml")
TARGET = Path("lib/accessibility_settings.dart")

ACCESSIBILITY_B64 = """"""

def run(command):
    print("$ " + " ".join(command))
    return subprocess.run(command, check=True)

for path in [MAIN, PUBSPEC]:
    if not path.exists():
        raise SystemExit(
            f"Gerekli dosya bulunamadı: {path}\n"
            "Kurulumu BilgiRotasi deposunun ana klasöründe çalıştır."
        )

branch = subprocess.check_output(
    ["git", "branch", "--show-current"],
    text=True,
).strip()

if branch != "main":
    raise SystemExit(
        "Bu geliştirme yalnızca main dalına kurulabilir.\n"
        f"Şu anki dal: {branch or '(belirsiz)'}\n"
        "Önce: git switch main"
    )

main = MAIN.read_text(encoding="utf-8")
pubspec = PUBSPEC.read_text(encoding="utf-8")

if (
    "part 'accessibility_settings.dart';" in main
    or TARGET.exists()
):
    raise SystemExit(
        "Ayarlar ve erişilebilirlik sistemi zaten kurulmuş görünüyor."
    )

required = [
    "part 'visual_collection.dart';",
    "await VisualCollectionService.initialize();",
    "class BilgiRotasiApp",
    "return MaterialApp(",
    "const GameplayBoostSettingsButton(),",
    "const CollectionHomeButton(),",
    "class _SoloRouteSetupScreenState",
    "class _PlayerSetupScreenState",
    "String get _preferredQuestionDifficulty",
    "class BoardPainter extends CustomPainter",
    "class _WinnerScreenState",
    "HapticFeedback.",
    "Bilgi Rotası • Sürüm 1.26",
]

for marker in required:
    if marker not in main:
        raise SystemExit(
            f"Beklenen main.dart bölümü bulunamadı: {marker}"
        )

version_match = re.search(
    r"^version:\s*(\d+)\.(\d+)\.(\d+)\+(\d+)\s*$",
    pubspec,
    flags=re.MULTILINE,
)

if version_match is None:
    raise SystemExit("pubspec.yaml sürüm satırı okunamadı.")

major, minor, patch, build = map(
    int,
    version_match.groups(),
)

if (major, minor) != (1, 26):
    raise SystemExit(
        "Bu paket 1.26.x sürümü için hazırlandı.\n"
        f"Depodaki sürüm: {major}.{minor}.{patch}+{build}"
    )

new_version = f"1.27.0+{build + 1}"

backup_dir = Path(tempfile.mkdtemp(
    prefix="bilgi_rotasi_accessibility_"
))
committed = False

try:
    shutil.copy2(MAIN, backup_dir / "main.dart")
    shutil.copy2(PUBSPEC, backup_dir / "pubspec.yaml")

    TARGET.write_text(
        base64.b64decode(
            ACCESSIBILITY_B64
        ).decode("utf-8"),
        encoding="utf-8",
    )

    main = main.replace(
        "part 'visual_collection.dart';",
        "part 'visual_collection.dart';\n"
        "part 'accessibility_settings.dart';",
        1,
    )

    init_marker = """  try {
    await VisualCollectionService.initialize();
  } catch (_) {
    // Koleksiyon sistemi açılamasa bile oyun devam eder.
  }

  runApp(const BilgiRotasiApp());"""

    if init_marker not in main:
        raise RuntimeError(
            "Ayar sistemi başlangıç noktası bulunamadı."
        )

    main = main.replace(
        init_marker,
        """  try {
    await VisualCollectionService.initialize();
  } catch (_) {
    // Koleksiyon sistemi açılamasa bile oyun devam eder.
  }

  try {
    await AppPreferencesService.initialize();
  } catch (_) {
    // Erişilebilirlik ayarları açılamasa bile oyun devam eder.
  }

  runApp(const BilgiRotasiApp());""",
        1,
    )

    material_marker = """        ),
      ),
      home: FutureBuilder<QuestionBank>("""

    if material_marker not in main:
        raise RuntimeError(
            "Uygulama yazı ölçeği ekleme noktası bulunamadı."
        )

    main = main.replace(
        material_marker,
        """        ),
      ),
      builder: (context, child) {
        return AccessibilityAppFrame(
          child: child ?? const SizedBox.shrink(),
        );
      },
      home: FutureBuilder<QuestionBank>(""",
        1,
    )

    sound_volume_marker = """          volume * atmosphere.volumeMultiplier
        ).clamp(0.0, 1.0).toDouble(),"""

    if sound_volume_marker not in main:
        raise RuntimeError(
            "Ana ses seviyesi entegrasyon noktası bulunamadı."
        )

    main = main.replace(
        sound_volume_marker,
        """          volume *
              atmosphere.volumeMultiplier *
              AppPreferencesService.soundMultiplier
        ).clamp(0.0, 1.0).toDouble(),""",
        1,
    )

    home_init_marker = """  void initState() {
    super.initState();
    _reloadSavedGame();
  }"""

    if home_init_marker not in main:
        raise RuntimeError(
            "İlk açılış eğitimi ekleme noktası bulunamadı."
        )

    main = main.replace(
        home_init_marker,
        """  void initState() {
    super.initState();
    _reloadSavedGame();

    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted) {
        unawaited(
          FirstRunTutorial.showIfNeeded(context),
        );
      }
    });
  }""",
        1,
    )

    home_button_marker = """                const CollectionHomeButton(),
                const SizedBox(height: 16),
                _buildNewGameCard(),"""

    if home_button_marker not in main:
        raise RuntimeError(
            "Ana ekran ayarlar düğmesi ekleme noktası bulunamadı."
        )

    main = main.replace(
        home_button_marker,
        """                const CollectionHomeButton(),
                const SizedBox(height: 10),
                const AccessibilitySettingsButton(),
                const SizedBox(height: 16),
                _buildNewGameCard(),""",
        1,
    )

    solo_start = main.index(
        "class _SoloRouteSetupScreenState"
    )
    solo_end = main.index(
        "class MarathonSetupScreen",
        solo_start,
    )
    solo_block = main[solo_start:solo_end]

    solo_name_marker = """  final TextEditingController _nameController =
      TextEditingController(text: 'Oyuncu');"""

    if solo_name_marker not in solo_block:
        raise RuntimeError(
            "Serbest Rota oyuncu adı noktası bulunamadı."
        )

    solo_block = solo_block.replace(
        solo_name_marker,
        """  final TextEditingController _nameController =
      TextEditingController(
        text: AppPreferencesService
            .current.defaultPlayerName,
      );""",
        1,
    )

    if "int _colorIndex = 1;" not in solo_block:
        raise RuntimeError(
            "Serbest Rota renk noktası bulunamadı."
        )

    solo_block = solo_block.replace(
        "int _colorIndex = 1;",
        "int _colorIndex = AppPreferencesService\n"
        "      .current.defaultColorIndex;",
        1,
    )

    main = (
        main[:solo_start]
        + solo_block
        + main[solo_end:]
    )

    setup_start = main.index(
        "class _PlayerSetupScreenState"
    )
    setup_end = main.index(
        "class WinnerScreen",
        setup_start,
    )
    setup_block = main[setup_start:setup_end]

    controller_marker = """  final List<TextEditingController> _controllers = List.generate(
    6,
    (index) => TextEditingController(text: 'Oyuncu ${index + 1}'),
  );"""

    if controller_marker not in setup_block:
        raise RuntimeError(
            "Çok oyunculu ad varsayılanı bulunamadı."
        )

    setup_block = setup_block.replace(
        controller_marker,
        """  final List<TextEditingController> _controllers =
      List.generate(
    6,
    (index) => TextEditingController(
      text: index == 0
          ? AppPreferencesService
              .current.defaultPlayerName
          : 'Oyuncu ${index + 1}',
    ),
  );""",
        1,
    )

    pawn_marker = """  final List<int> _selectedPawnTypes = List<int>.generate(
    6,
    (index) => index,
  );"""

    if pawn_marker not in setup_block:
        raise RuntimeError(
            "Çok oyunculu favori piyon noktası bulunamadı."
        )

    setup_block = setup_block.replace(
        pawn_marker,
        """  final List<int> _selectedPawnTypes =
      List<int>.generate(
    6,
    (index) => index == 0
        ? VisualCollectionService
            .current.favoritePawn
        : index,
  );""",
        1,
    )

    main = (
        main[:setup_start]
        + setup_block
        + main[setup_end:]
    )

    difficulty_marker = """  String get _preferredQuestionDifficulty {
    final badgeCount = _currentPlayer.badges.length;"""

    if difficulty_marker not in main:
        raise RuntimeError(
            "Çocuk modu soru seviyesi noktası bulunamadı."
        )

    main = main.replace(
        difficulty_marker,
        """  String get _preferredQuestionDifficulty {
    if (AppPreferencesService.current.childMode) {
      return 'Kolay';
    }

    final badgeCount = _currentPlayer.badges.length;""",
        1,
    )

    board_legend_marker = """            Padding(
              padding: const EdgeInsets.fromLTRB(12, 4, 12, 14),
              child: Text(
                _status,"""

    if board_legend_marker not in main:
        raise RuntimeError(
            "Kategori destek açıklaması ekleme noktası bulunamadı."
        )

    main = main.replace(
        board_legend_marker,
        """            const AccessibilityCategoryLegend(),
            Padding(
              padding: const EdgeInsets.fromLTRB(12, 4, 12, 14),
              child: Text(
                _status,""",
        1,
    )

    sound_field_marker = "  bool _soundEnabled = true;"

    if sound_field_marker not in main:
        raise RuntimeError(
            "Oyun ses durumu noktası bulunamadı."
        )

    main = main.replace(
        sound_field_marker,
        """  bool _soundEnabled =
      AppPreferencesService.current.soundEnabled;""",
        1,
    )

    sound_toggle_marker = """              setState(() {
                _soundEnabled = willEnable;
                SoundFx.setEnabled(willEnable);
              });

              if (willEnable) {"""

    if sound_toggle_marker not in main:
        raise RuntimeError(
            "Oyun içi ses düğmesi kayıt noktası bulunamadı."
        )

    main = main.replace(
        sound_toggle_marker,
        """              setState(() {
                _soundEnabled = willEnable;
              });

              await AppPreferencesService
                  .setSoundEnabled(willEnable);

              if (willEnable) {""",
        1,
    )

    winner_repeat_marker = """    _confettiController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 3600),
    )..repeat();"""

    if winner_repeat_marker not in main:
        raise RuntimeError(
            "Minimum animasyon şampiyon ekranı noktası bulunamadı."
        )

    main = main.replace(
        winner_repeat_marker,
        """    _confettiController = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 3600),
    );

    if (AppPreferencesService
            .current.animationMode ==
        'minimal') {
      _confettiController.value = 0.35;
    } else {
      _confettiController.repeat();
    }""",
        1,
    )

    # Ana dosyadaki bütün titreşimler artık kullanıcı ayarına uyar.
    main = main.replace(
        "HapticFeedback.",
        "GameHaptics.",
    )

    main, version_count = re.subn(
        r"Bilgi Rotası • Sürüm 1\.26(?:\.\d+)?",
        "Bilgi Rotası • Sürüm 1.27",
        main,
        count=1,
    )

    if version_count != 1:
        raise RuntimeError(
            "Ana menü sürüm yazısı güncellenemedi."
        )

    pubspec = re.sub(
        r"^version:\s*.*$",
        f"version: {new_version}",
        pubspec,
        count=1,
        flags=re.MULTILINE,
    )

    MAIN.write_text(main, encoding="utf-8")
    PUBSPEC.write_text(pubspec, encoding="utf-8")

    checks = {
        MAIN: [
            "part 'accessibility_settings.dart';",
            "AppPreferencesService.initialize",
            "AccessibilityAppFrame(",
            "AppPreferencesService.soundMultiplier",
            "FirstRunTutorial.showIfNeeded",
            "const AccessibilitySettingsButton()",
            "const AccessibilityCategoryLegend()",
            "GameHaptics.mediumImpact",
            "Bilgi Rotası • Sürüm 1.27",
        ],
        TARGET: [
            "class AppPreferencesService",
            "class AccessibilitySettingsScreen",
            "class AccessibilityAppFrame",
            "class AccessibilityCategoryLegend",
            "class FirstRunTutorial",
            "Çocuk modu",
            "Kategori destek modu",
            "Animasyon yoğunluğu",
        ],
        PUBSPEC: [f"version: {new_version}"],
    }

    for path, markers in checks.items():
        text = path.read_text(encoding="utf-8")

        for marker in markers:
            if marker not in text:
                raise RuntimeError(
                    f"Kurulum doğrulaması başarısız: "
                    f"{path} / {marker}"
                )

    if shutil.which("dart"):
        run([
            "dart",
            "format",
            "lib/main.dart",
            "lib/accessibility_settings.dart",
        ])

    run(["git", "diff", "--check"])

    if shutil.which("flutter"):
        run([
            "flutter",
            "analyze",
            "--no-fatal-infos",
        ])

    run([
        "git",
        "add",
        "lib/main.dart",
        "lib/accessibility_settings.dart",
        "pubspec.yaml",
    ])

    changed = subprocess.run(
        ["git", "diff", "--cached", "--quiet"],
        check=False,
    ).returncode != 0

    if not changed:
        raise RuntimeError(
            "Commit edilecek değişiklik bulunamadı."
        )

    run([
        "git",
        "commit",
        "-m",
        "Ayarlar erisilebilirlik cocuk modu ve ilk acilis egitimi",
    ])
    committed = True

    run(["git", "push", "origin", "main"])

except Exception as error:
    if not committed:
        shutil.copy2(
            backup_dir / "main.dart",
            MAIN,
        )
        shutil.copy2(
            backup_dir / "pubspec.yaml",
            PUBSPEC,
        )

        if TARGET.exists():
            TARGET.unlink()

        subprocess.run(
            [
                "git",
                "reset",
                "--",
                "lib/main.dart",
                "lib/accessibility_settings.dart",
                "pubspec.yaml",
            ],
            check=False,
        )

    print("")
    print("❌ Kurulum tamamlanamadı.")
    print(str(error))

    if committed:
        print(
            "Commit oluşturuldu fakat push başarısız oldu. "
            "Tekrar dene: git push origin main"
        )
    else:
        print(
            "Dosyalar önceki hâline otomatik döndürüldü."
        )

    raise SystemExit(1)

finally:
    shutil.rmtree(backup_dir, ignore_errors=True)

print("")
print("✅ Varsayılan oyuncu adı ve Serbest Rota rengi eklendi.")
print("✅ Normal, Büyük ve Çok Büyük yazı seçenekleri eklendi.")
print("✅ Çocuk modu ve Kolay tahta soruları eklendi.")
print("✅ Kategori destek modu ve tahta açıklama şeridi eklendi.")
print("✅ Kalıcı ses, ana ses seviyesi ve titreşim ayarları eklendi.")
print("✅ Tam, Azaltılmış ve Minimum animasyon seçenekleri eklendi.")
print("✅ Dört ekranlık ilk açılış eğitimi eklendi.")
print("✅ İlk oyuncuya kayıtlı ad ve favori piyon uygulanıyor.")
print("✅ questions.json dosyasına dokunulmadı.")
print(f"✅ Yeni sürüm: {new_version}")
print("✅ Değişiklikler GitHub main dalına gönderildi.")
